import { getExtensionPointFromFilePath, getHubspotImportExtensionPoint, isImportOutsideExtensionPoint, mapExtensionPointToImportDirectory, } from "../../utils/extension-point-utils.js";
describe('extension-point-utils', () => {
    describe('getExtensionPointFromFilePath', () => {
        it('should return the extension point for valid paths', () => {
            expect(getExtensionPointFromFilePath('src/app/cards/MyCard.tsx')).toBe('cards');
            expect(getExtensionPointFromFilePath('src/app/extensions/MyExtension.tsx')).toBe('extensions');
            expect(getExtensionPointFromFilePath('src/app/settings/MySettings.tsx')).toBe('settings');
            expect(getExtensionPointFromFilePath('src/app/pages/MyPage.tsx')).toBe('pages');
        });
        it('should return the extension point for nested file paths', () => {
            expect(getExtensionPointFromFilePath('src/app/cards/components/nested/MyCard.tsx')).toBe('cards');
            expect(getExtensionPointFromFilePath('src/app/extensions/hooks/useCustom.ts')).toBe('extensions');
        });
        it('should return the first extension point when nested directories have extension point names', () => {
            expect(getExtensionPointFromFilePath('src/app/pages/cards/CardFile.tsx')).toBe('pages');
            expect(getExtensionPointFromFilePath('src/app/extensions/settings/SettingsComponent.tsx')).toBe('extensions');
            expect(getExtensionPointFromFilePath('src/app/cards/pages/nested/File.tsx')).toBe('cards');
        });
        it('should return the extension point when path has leading directories', () => {
            expect(getExtensionPointFromFilePath('/Users/dev/project/src/app/cards/MyCard.tsx')).toBe('cards');
            expect(getExtensionPointFromFilePath('project/src/app/settings/Settings.tsx')).toBe('settings');
        });
        it('should return null for paths without src/app pattern', () => {
            expect(getExtensionPointFromFilePath('app/cards/MyCard.tsx')).toBeNull();
            expect(getExtensionPointFromFilePath('src/cards/MyCard.tsx')).toBeNull();
            expect(getExtensionPointFromFilePath('cards/MyCard.tsx')).toBeNull();
        });
        it('should return null for invalid extension points', () => {
            expect(getExtensionPointFromFilePath('src/app/unknown/MyComponent.tsx')).toBeNull();
            expect(getExtensionPointFromFilePath('src/app/components/MyComponent.tsx')).toBeNull();
        });
    });
    describe('getHubspotImportExtensionPoint', () => {
        it('should return the extension point for valid extension-specific imports', () => {
            expect(getHubspotImportExtensionPoint('@hubspot/ui-extensions/crm')).toBe('crm');
            expect(getHubspotImportExtensionPoint('@hubspot/ui-extensions/crm/hooks')).toBe('crm');
            expect(getHubspotImportExtensionPoint('@hubspot/ui-extensions/settings')).toBe('settings');
            expect(getHubspotImportExtensionPoint('@hubspot/ui-extensions/settings/types')).toBe('settings');
            expect(getHubspotImportExtensionPoint('@hubspot/ui-extensions/pages')).toBe('pages');
        });
        it('should return null for base package imports without extension point', () => {
            expect(getHubspotImportExtensionPoint('@hubspot/ui-extensions')).toBeNull();
            expect(getHubspotImportExtensionPoint('@hubspot/ui-extensions/hooks')).toBeNull();
            expect(getHubspotImportExtensionPoint('@hubspot/ui-extensions/components')).toBeNull();
        });
    });
    describe('mapExtensionPointToImportDirectory', () => {
        it('should map extensions to crm', () => {
            expect(mapExtensionPointToImportDirectory('extensions')).toBe('crm');
        });
        it('should map cards to crm', () => {
            expect(mapExtensionPointToImportDirectory('cards')).toBe('crm');
        });
        it('should return the same value for extension points without special mapping', () => {
            expect(mapExtensionPointToImportDirectory('settings')).toBe('settings');
            expect(mapExtensionPointToImportDirectory('pages')).toBe('pages');
        });
    });
    describe('isImportOutsideExtensionPoint', () => {
        describe('in cards directory', () => {
            it('should return false for imports within cards directory', () => {
                expect(isImportOutsideExtensionPoint('/project/src/app/cards/Component.tsx', './utils')).toBe(false);
                expect(isImportOutsideExtensionPoint('/project/src/app/cards/Component.tsx', './components/Button')).toBe(false);
            });
            it('should return false for imports going up but staying within cards', () => {
                expect(isImportOutsideExtensionPoint('/project/src/app/cards/nested/Component.tsx', '../utils')).toBe(false);
                expect(isImportOutsideExtensionPoint('/project/src/app/cards/nested/deep/Component.tsx', '../../utils')).toBe(false);
            });
            it('should return true for imports escaping cards directory', () => {
                expect(isImportOutsideExtensionPoint('/project/src/app/cards/Component.tsx', '../shared/utils')).toBe(true);
                expect(isImportOutsideExtensionPoint('/project/src/app/cards/nested/Component.tsx', '../../lib/constants')).toBe(true);
            });
            it('should return true for deeply nested imports escaping cards', () => {
                expect(isImportOutsideExtensionPoint('/project/src/app/cards/nested/deep/Component.tsx', '../../../lib/utils')).toBe(true);
            });
        });
        describe('in extensions directory', () => {
            it('should return false for imports within extensions directory', () => {
                expect(isImportOutsideExtensionPoint('/project/src/app/extensions/Component.tsx', './utils')).toBe(false);
            });
            it('should return true for imports escaping extensions directory', () => {
                expect(isImportOutsideExtensionPoint('/project/src/app/extensions/Component.tsx', '../shared/utils')).toBe(true);
            });
        });
        describe('in settings directory', () => {
            it('should return false for imports within settings directory', () => {
                expect(isImportOutsideExtensionPoint('/project/src/app/settings/Config.tsx', './utils')).toBe(false);
            });
            it('should return true for imports escaping settings directory', () => {
                expect(isImportOutsideExtensionPoint('/project/src/app/settings/Config.tsx', '../shared/utils')).toBe(true);
            });
        });
        describe('in pages directory', () => {
            it('should return false for imports within pages directory', () => {
                expect(isImportOutsideExtensionPoint('/project/src/app/pages/Dashboard.tsx', './components/Widget')).toBe(false);
            });
            it('should return true for imports escaping pages directory', () => {
                expect(isImportOutsideExtensionPoint('/project/src/app/pages/Dashboard.tsx', '../shared/utils')).toBe(true);
            });
        });
        describe('outside extension points', () => {
            it('should return false for files not in extension point directories', () => {
                expect(isImportOutsideExtensionPoint('/project/src/lib/utils.ts', '../config/constants')).toBe(false);
                expect(isImportOutsideExtensionPoint('/project/src/app/shared/helper.ts', '../../lib/utils')).toBe(false);
            });
        });
        describe('edge cases', () => {
            it('should handle complex relative paths correctly', () => {
                expect(isImportOutsideExtensionPoint('/project/src/app/cards/nested/Component.tsx', './../utils')).toBe(false);
            });
            it('should correctly identify imports at the boundary', () => {
                // Going to exactly the cards directory root is still within bounds
                expect(isImportOutsideExtensionPoint('/project/src/app/cards/nested/Component.tsx', '../')).toBe(false);
                // Going beyond the cards directory root is outside bounds
                expect(isImportOutsideExtensionPoint('/project/src/app/cards/Component.tsx', '../')).toBe(true);
            });
            it('should handle paths with platform-specific separators', () => {
                // Unix-style path
                expect(isImportOutsideExtensionPoint('/Users/dev/project/src/app/cards/Component.tsx', '../shared/utils')).toBe(true);
                // This test works because path.resolve handles both formats
                expect(isImportOutsideExtensionPoint('/Users/dev/project/src/app/cards/nested/Component.tsx', '../utils')).toBe(false);
            });
        });
    });
});
